import org.springframework.stereotype.Component;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.ByteBuffer;
import java.security.SecureRandom;
import java.time.Instant;

@Component
public class TotpService {

    private final SecureRandom random = new SecureRandom();

    public String generateBase32Secret(int bytes) {
        byte[] b = new byte[bytes];
        random.nextBytes(b);
        return Base32.encode(b);
    }

    public boolean verifyCode(String base32Secret, String code, int timeStepSeconds, int digits, int window) {
        if (base32Secret == null || base32Secret.isBlank() || code == null) return false;
        String normalized = code.trim().replace(" ", "");
        if (normalized.length() != digits) return false;
        long nowStep = Instant.now().getEpochSecond() / timeStepSeconds;
        for (int i = -window; i <= window; i++) {
            String candidate = totp(base32Secret, nowStep + i, digits);
            if (candidate.equals(normalized)) return true;
        }
        return false;
    }

    public String totp(String base32Secret, long timeStep, int digits) {
        byte[] key = Base32.decode(base32Secret);
        byte[] data = ByteBuffer.allocate(8).putLong(timeStep).array();
        byte[] hmac = hmacSha1(key, data);

        int offset = hmac[hmac.length - 1] & 0x0F;
        int binary =
                ((hmac[offset] & 0x7f) << 24) |
                        ((hmac[offset + 1] & 0xff) << 16) |
                        ((hmac[offset + 2] & 0xff) << 8) |
                        (hmac[offset + 3] & 0xff);

        int otp = binary % (int) Math.pow(10, digits);
        return String.format("%0" + digits + "d", otp);
    }

    private byte[] hmacSha1(byte[] key, byte[] data) {
        try {
            Mac mac = Mac.getInstance("HmacSHA1");
            mac.init(new SecretKeySpec(key, "HmacSHA1"));
            return mac.doFinal(data);
        } catch (Exception e) {
            throw new IllegalStateException(e);
        }
    }
}
package com.example.mfa.service;

import java.io.ByteArrayOutputStream;

final class Base32 {
    private static final char[] ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567".toCharArray();
    private static final int[] LOOKUP = new int[128];

    static {
        for (int i = 0; i < LOOKUP.length; i++) LOOKUP[i] = -1;
        for (int i = 0; i < ALPHABET.length; i++) LOOKUP[ALPHABET[i]] = i;
    }

    static String encode(byte[] data) {
        StringBuilder sb = new StringBuilder((data.length * 8 + 4) / 5);
        int buffer = 0;
        int bitsLeft = 0;
        for (byte b : data) {
            buffer <<= 8;
            buffer |= (b & 0xFF);
            bitsLeft += 8;
            while (bitsLeft >= 5) {
                int idx = (buffer >> (bitsLeft - 5)) & 0x1F;
                bitsLeft -= 5;
                sb.append(ALPHABET[idx]);
            }
        }
        if (bitsLeft > 0) {
            int idx = (buffer << (5 - bitsLeft)) & 0x1F;
            sb.append(ALPHABET[idx]);
        }
        return sb.toString();
    }

    static byte[] decode(String s) {
        if (s == null) return new byte[0];
        String input = s.trim().replace("=", "").toUpperCase();
        int buffer = 0;
        int bitsLeft = 0;
        ByteArrayOutputStream out = new ByteArrayOutputStream();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (c >= LOOKUP.length) continue;
            int val = LOOKUP[c];
            if (val < 0) continue;
            buffer <<= 5;
            buffer |= val;
            bitsLeft += 5;
            if (bitsLeft >= 8) {
                out.write((buffer >> (bitsLeft - 8)) & 0xFF);
                bitsLeft -= 8;
            }
        }
        return out.toByteArray();
    }

    private Base32() {}
}
package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import org.springframework.stereotype.Service;

import java.util.List;

@Service
public class AuthService {

    private final UserService userService;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;

    public AuthService(UserService userService, TotpService totpService, BackupCodeService backupCodeService) {
        this.userService = userService;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
    }

    public AuthResult passwordLogin(String username, String password) {
        var opt = userService.findByUsername(username);
        if (opt.isEmpty()) return AuthResult.invalid("Invalid credentials");
        AppUser user = opt.get();
        if (!userService.verifyPassword(user, password)) return AuthResult.invalid("Invalid credentials");

        if (!user.isMfaEnabled()) {
            return AuthResult.success(user.getId(), false);
        }
        return AuthResult.mfaRequired(user.getId());
    }

    public AuthResult verifySecondFactor(Long userId, String totpCode) {
        var opt = userService.findById(userId);
        if (opt.isEmpty()) return AuthResult.invalid("Invalid session");
        AppUser user = opt.get();
        if (!user.isMfaEnabled()) return AuthResult.success(user.getId(), false);

        boolean ok = totpService.verifyCode(user.getTotpSecret(), totpCode, 30, 6, 1);
        return ok ? AuthResult.success(user.getId(), true) : AuthResult.invalid("Invalid MFA code");
    }

    public AuthResult verifyWithBackupCode(Long userId, String backupCode) {
        var opt = userService.findById(userId);
        if (opt.isEmpty()) return AuthResult.invalid("Invalid session");
        AppUser user = opt.get();
        if (!user.isMfaEnabled()) return AuthResult.success(user.getId(), false);

        boolean ok = backupCodeService.consumeBackupCode(userId, backupCode);
        return ok ? AuthResult.success(user.getId(), true) : AuthResult.invalid("Invalid backup code");
    }

    public MfaEnableResult enableMfaAndCreateBackupCodes(Long userId) {
        var opt = userService.findById(userId);
        if (opt.isEmpty()) throw new IllegalArgumentException("User not found");
        AppUser user = opt.get();

        String secret = totpService.generateBase32Secret(20);
        userService.enableMfa(user, secret);

        List<String> codes = backupCodeService.generateAndStoreNewCodes(user, 10);
        return new MfaEnableResult(user.getId(), secret, codes);
    }
}
package com.example.mfa.service;

public class AuthResult {
    private boolean ok;
    private boolean mfaRequired;
    private Long userId;
    private String message;
    private boolean mfaSatisfied;

    public static AuthResult success(Long userId, boolean mfaSatisfied) {
        AuthResult r = new AuthResult();
        r.ok = true;
        r.userId = userId;
        r.mfaRequired = false;
        r.mfaSatisfied = mfaSatisfied;
        return r;
    }

    public static AuthResult mfaRequired(Long userId) {
        AuthResult r = new AuthResult();
        r.ok = true;
        r.userId = userId;
        r.mfaRequired = true;
        r.mfaSatisfied = false;
        return r;
    }

    public static AuthResult invalid(String message) {
        AuthResult r = new AuthResult();
        r.ok = false;
        r.message = message;
        return r;
    }

    public boolean isOk() { return ok; }
    public boolean isMfaRequired() { return mfaRequired; }
    public Long getUserId() { return userId; }
    public String getMessage() { return message; }
    public boolean isMfaSatisfied() { return mfaSatisfied; }

    public void setOk(boolean ok) { this.ok = ok; }
    public void setMfaRequired(boolean mfaRequired) { this.mfaRequired = mfaRequired; }
    public void setUserId(Long userId) { this.userId = userId; }
    public void setMessage(String message) { this.message = message; }
    public void setMfaSatisfied(boolean mfaSatisfied) { this.mfaSatisfied = mfaSatisfied; }
}
