public class ApiResponse<T> {
    private boolean ok;
    private String message;
    private T data;

    public ApiResponse() {}

    public ApiResponse(boolean ok, String message, T data) {
        this.ok = ok;
        this.message = message;
        this.data = data;
    }

    public static <T> ApiResponse<T> ok(T data) {
        return new ApiResponse<>(true, null, data);
    }

    public static <T> ApiResponse<T> fail(String message) {
        return new ApiResponse<>(false, message, null);
    }

    public boolean isOk() { return ok; }
    public String getMessage() { return message; }
    public T getData() { return data; }

    public void setOk(boolean ok) { this.ok = ok; }
    public void setMessage(String message) { this.message = message; }
    public void setData(T data) { this.data = data; }
}
package com.example.mfa.web;

import com.example.mfa.service.AuthResult;
import com.example.mfa.service.AuthService;
import com.example.mfa.service.MfaEnableResult;
import com.example.mfa.service.UserService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api")
public class AuthController {

    private final UserService userService;
    private final AuthService authService;

    public AuthController(UserService userService, AuthService authService) {
        this.userService = userService;
        this.authService = authService;
    }

    @PostMapping("/register")
    public ResponseEntity<ApiResponse<Long>> register(@RequestBody RegisterRequest req) {
        var u = userService.register(req.getUsername(), req.getPassword());
        return ResponseEntity.ok(ApiResponse.ok(u.getId()));
    }

    @PostMapping("/login")
    public ResponseEntity<ApiResponse<AuthResult>> login(@RequestBody LoginRequest req) {
        AuthResult res = authService.passwordLogin(req.getUsername(), req.getPassword());
        return ResponseEntity.ok(res.isOk() ? ApiResponse.ok(res) : ApiResponse.fail(res.getMessage()));
    }

    @PostMapping("/mfa/enable")
    public ResponseEntity<ApiResponse<MfaEnableResult>> enableMfa(@RequestBody EnableMfaRequest req) {
        MfaEnableResult res = authService.enableMfaAndCreateBackupCodes(req.getUserId());
        return ResponseEntity.ok(ApiResponse.ok(res));
    }

    @PostMapping("/mfa/verify-totp")
    public ResponseEntity<ApiResponse<AuthResult>> verifyTotp(@RequestBody VerifyTotpRequest req) {
        AuthResult res = authService.verifySecondFactor(req.getUserId(), req.getCode());
        return ResponseEntity.ok(res.isOk() ? ApiResponse.ok(res) : ApiResponse.fail(res.getMessage()));
    }

    @PostMapping("/mfa/verify-backup-code")
    public ResponseEntity<ApiResponse<AuthResult>> verifyBackupCode(@RequestBody VerifyBackupCodeRequest req) {
        AuthResult res = authService.verifyWithBackupCode(req.getUserId(), req.getBackupCode());
        return ResponseEntity.ok(res.isOk() ? ApiResponse.ok(res) : ApiResponse.fail(res.getMessage()));
    }
}
